INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1079, 82625, 5, 379, '秋晨絮语', '醒在初凉的清晨，让一夜的露水驱走昨日的梦幻和清晨的迷惘。轻轻旋开今春旅游时残留的那瓶润肤露，熟悉的味道夹着西湖纷的柳絮 ，黄山飘渺的云雾，滋润了我的双眸。
<br>    秋天来了，丰收过后是满目的疮痍，一夜之间，大自然褪尽夏的墨绿染上了日暮的鲜红。漫步在夹道的树间，任长长的裙裾卷起一地的落红，似双双蝴蝶嬉闹于足旁。闭上眼，静静地感受，细细地回想，却发现受过的伤，流过的泪早已云淡风轻。抬眼望，守候了一夜的繁星早已睡去，不见踪影，如霜的月正逐渐隐没在泛白的天际，突然想起席慕容的：“大自然里有些事物都不会改变，改变的只是人的心情。”是啊，那轮照过了长城，照过了洞庭的明月，却再也无法，用他如刃的光袭我以夜夜忧......', '醒在初凉的清晨，让一夜的露水驱走昨日的梦幻和清晨的迷惘。轻轻旋开今春旅游时残留的那瓶润肤露，熟悉的味道夹着西湖纷的柳絮 ，黄山飘渺的云雾，滋润了我的双眸。

秋天来了，丰收过后是满目的疮痍，一夜之间，大自然褪尽夏的墨绿染上了日暮的鲜红。漫步在夹道的树间，任长长的裙裾卷起一地的落红，似双双蝴蝶嬉闹于足旁。闭上眼，静静地感受，细细地回想，却发现受过的伤，流过的泪早已云淡风轻。抬眼望，守候了一夜的繁星早已睡去，不见踪影，如霜的月正逐渐隐没在泛白的天际，突然想起席慕容的：“大自然里有些事物都不会改变，改变的只是人的心情。”是啊，那轮照过了长城，照过了洞庭的明月，却再也无法，用他如刃的光袭我以夜夜忧......', NULL, '2001-01-03 23:37:00', 5, '20021120163136_bbsid_82625_board_5_510917fe1f.html', '20021120163136');
